type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

const MAIN_ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PER_ITEM = 25;
const COMPONENT_BLOCK_BASE = 60;

const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE;

const componentsBase = (items: Item[]): number => {
  if (items.length === 3) return COMPONENT_BLOCK_BASE;
  return items.length * COMPONENT_BASE_PER_ITEM;
};

const policyBase = (items: Item[]): number => {
  const mainItems = items.filter(isMainItem);
  const components = items.filter((i) => !isMainItem(i));
  const mainTotal = mainItems.reduce((sum, item) => sum + MAIN_ITEM_BASE[item.type], 0);
  return mainTotal + componentsBase(components);
};

export const processScenario = (
  scenario: Scenario,
): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    const base = policyBase(step.items);
    const firstInsurance = base * 0.1;
    return { premium: Math.ceil(base + firstInsurance + 5) };
  });
  return { results };
};

