type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const baseFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

export const processScenario = (
  scenario: Scenario,
): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    const policyBase = step.items.reduce((sum, item) => sum + baseFor(item), 0);
    const firstInsurance = policyBase * 0.1;
    return { premium: Math.ceil(policyBase + firstInsurance + 5) };
  });
  return { results };
};

