  const countsByType = new Map<string, number>();
  for (const item of items) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of countsByType.values()) {
    total += count === 3 ? COMPONENT_BLOCK_BASE : count * COMPONENT_BASE_PER_ITEM;
  }
  return total;
};

const mainItemContribution = (item: Item): number => {
  const base = MAIN_ITEM_BASE[item.type];
  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
  return base + curseSurcharge;
};

const policyBase = (items: Item[]): number => {
  const mainItems = items.filter(isMainItem);
  const components = items.filter((i) => !isMainItem(i));
  const mainTotal = mainItems.reduce((sum, item) => sum + mainItemContribution(item), 0);
  return mainTotal + componentsBase(components);
};

export const processScenario = (
  scenario: Scenario,
): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    const base = policyBase(step.items);
    const firstInsurance = base * 0.1;
    return { premium: Math.ceil(base + firstInsurance + 5) };
  });
  return { results };
};

