  let totalPayout = 0;
  for (const damage of damages) {
    const item = findPolicyItem(policy, damage.itemType);
    if (!item) continue;
    // simple base case: full reimbursement minus deductible
    const payout = Math.max(0, Math.floor(damage.amount - DEDUCTIBLE));
    const actualPayout = Math.min(payout, policy.remainingCap - totalPayout);
    totalPayout += Math.max(0, actualPayout);
