  const followUp = quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
  return Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
};

const computeDamagePayout = (item: Item, amount: number): number => {
  const reimbursable = amount * 0.5;
  // Will be expanded later
  const beforeDeductible = reimbursable;
  return Math.max(0, Math.floor(beforeDeductible - DEDUCTIBLE));
};

const findPolicyItem = (policy: Policy, itemType: string): Item | undefined =>
  policy.items.find((i) => i.type === itemType);

const processClaim = (policy: Policy, damages: Damage[]): ClaimResult => {
  let totalPayout = 0;
  for (const damage of damages) {
    const item = findPolicyItem(policy, damage.itemType);
    if (!item) continue;
    // simple base case: full reimbursement minus deductible
    const payout = Math.max(0, Math.floor(damage.amount - DEDUCTIBLE));
    const actualPayout = Math.min(payout, policy.remainingCap - totalPayout);
    totalPayout += Math.max(0, actualPayout);
  }
  policy.remainingCap -= totalPayout;
  return { payout: totalPayout, remainingCap: policy.remainingCap };
};

