const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type];

const itemInsuranceValue = (item: Item): number =>
  isMainItem(item) ? MAIN_ITEM_INSURANCE[item.type] : COMPONENT_INSURANCE;

